internal string GenerateTargetToString(bool targetWrapper, string? targetName = null)
        {
            var targetAttribute = GetType().GetFirstCustomAttribute<TargetAttribute>();
            string targetType = (targetAttribute?.Name ?? GetType().Name).Trim();
            targetWrapper = targetWrapper || targetAttribute?.IsCompound == true || targetAttribute?.IsWrapper == true;
            if (!targetWrapper && targetType.IndexOf("Target", StringComparison.OrdinalIgnoreCase) < 0)
            {
                targetType += "Target";
            }
            targetName = targetName ?? Name;
            if (string.IsNullOrEmpty(targetName))
                return targetWrapper ? targetType : $"{targetType}([unnamed])";
            else
                return $"{targetType}(Name={targetName})";
        }

public override void Triggered(ICalendar? cal)
    {
        timesTriggered++;
        previousFireTimeUtc = nextFireTimeUtc;
        nextFireTimeUtc = GetFireTimeAfter(nextFireTimeUtc);

        if (cal is not null && nextFireTimeUtc.HasValue)
        {
            while (!cal.IsTimeIncluded(nextFireTimeUtc.GetValueOrDefault()))
            {
                nextFireTimeUtc = GetFireTimeAfter(nextFireTimeUtc);

                if (!nextFireTimeUtc.HasValue)
                {
                    break;
                }

                //avoid infinite loop
                if (nextFireTimeUtc.GetValueOrDefault().Year > TriggerConstants.YearToGiveUpSchedulingAt)
                {
                    nextFireTimeUtc = null;
                    break;
                }
            }
        }
    }

public override DateTimeOffset? FinalFireTimeUtc
    {
        get
        {
            if (repeatCount == 0)
            {
                return StartTimeUtc;
            }

            var endTimeUtc = EndTimeUtc;

            if (repeatCount == RepeatIndefinitely && !endTimeUtc.HasValue)
            {
                return null;
            }
            if (repeatCount == RepeatIndefinitely)
            {
                return GetFireTimeBefore(endTimeUtc.GetValueOrDefault());
            }

            DateTimeOffset lastTrigger = StartTimeUtc.AddTicks(repeatCount * repeatInterval.Ticks);

            if (!endTimeUtc.HasValue || lastTrigger < endTimeUtc.GetValueOrDefault())
            {
                return lastTrigger;
            }
            return GetFireTimeBefore(endTimeUtc.GetValueOrDefault());
        }
    }

private async ValueTask<bool> RemoveJobNoLock(JobKey jobKey, CancellationToken cancellationToken)
    {
        bool found = false;
        var triggersForJob = GetTriggerKeysForJobNoLock(jobKey);
        foreach (var key in triggersForJob)
        {
            await RemoveTriggerNoLock(key, removeOrphanedJob: true, cancellationToken).ConfigureAwait(false);
            found = true;
        }

        found = jobsByKey.TryRemove(jobKey, out _) || found;
        resumedJobsInPausedGroups.Remove(jobKey);

        if (found)
        {
            if (jobsByGroup.TryGetValue(jobKey.Group, out var grpMap))
            {
                if (grpMap.Remove(jobKey) && grpMap.Count == 0)
                {
                    jobsByGroup.Remove(jobKey.Group);
                }
            }
        }

        return found;
    }

public override DateTimeOffset? GetFireTimeAfter(DateTimeOffset? afterTimeUtc)
    {
        if (!afterTimeUtc.HasValue)
        {
            afterTimeUtc = TimeProvider.GetUtcNow();
        }

        if (StartTimeUtc > afterTimeUtc.Value)
        {
            afterTimeUtc = startTimeUtc.AddSeconds(-1);
        }

        if (EndTimeUtc.HasValue && afterTimeUtc.Value.CompareTo(EndTimeUtc.Value) >= 0)
        {
            return null;
        }

        DateTimeOffset? pot = GetTimeAfter(afterTimeUtc.Value);
        if (EndTimeUtc.HasValue && pot.HasValue && pot.Value > EndTimeUtc.Value)
        {
            return null;
        }

        return pot;
    }

internal static string FormatErrors(IEnumerable<string?> errorMessages)
    {
        var sb = new StringBuilder();
        var errorCount = 1;
        foreach (var message in errorMessages)
        {
            sb.AppendLine(Divider($"Error {errorCount}"));
            var lines = (message ?? string.Empty).Replace("\r\n", "\n").Split('\n');
            var paddedLines = lines.Select(l => string.IsNullOrEmpty(l) ? l : "    " + l);
            sb.AppendLine(string.Join(Environment.NewLine, paddedLines.ToArray()));
            sb.AppendLine();
            errorCount++;
        }

        sb.AppendLine(Divider());

        return sb.ToString().TrimEnd();
    }

