                _pageSizeLimit = pageSizeLimit * 1024 * 1024;
                _currentPageSize = 0;
            }

            if (retentionDays > 0)
            {
                _enableLogRetention = true;
                _retentionDays = retentionDays;
            }

            Writer = CreatePageLogWriter();
        }

public override void WriteLine(string message)
        {
            base.WriteLine(message);
            if (_enablePageLog)
            {
                int messageSize = UTF8Encoding.UTF8.GetByteCount(message);
                _currentPageSize += messageSize;
                if (_currentPageSize > _pageSizeLimit)
                {
                    Flush();
                    if (Writer != null)
                    {
                        Writer.Dispose();
                        Writer = null;
                    }

                    Writer = CreatePageLogWriter();
                    _currentPageSize = 0;
                }
            }

            Flush();
        }

private static async Task<HttpRequestMessage> CloneAsync(HttpRequestMessage request, Uri requestUri)
        {
            var clone = new HttpRequestMessage(request.Method, requestUri)
            {
                Version = request.Version
            };

            request.Headers.ForEach(header => clone.Headers.TryAddWithoutValidation(header.Key, header.Value));

            request.Options.ForEach(option => clone.Options.Set(new HttpRequestOptionsKey<object>(option.Key), option.Value));

            if (request.Content != null)
            {
                clone.Content = new ByteArrayContent(await request.Content.ReadAsByteArrayAsync().ConfigureAwait(false));

                request.Content.Headers.ForEach(header => clone.Content.Headers.TryAddWithoutValidation(header.Key, header.Value));
            }

            return clone;
        }

public Task<GrainAddress?> Register(GrainAddress address, GrainAddress? previousAddress)
    {
        ArgumentNullException.ThrowIfNull(address);

        var result = _entries.AddOrUpdate(
            address.GrainId,
            static (grainId, state) => state.Address,
            static (grainId, existing, state) =>
            {
                if (existing is null || state.PreviousAddress is { } prev && existing.Matches(prev) || state.Self.IsSiloDead(existing))
                {
                    return state.Address;
                }

                return existing;
            },
            (Self: this, Address: address, PreviousAddress: previousAddress));

        if (result is null || IsSiloDead(result))
        {
            return Task.FromResult<GrainAddress?>(null);
        }

        return Task.FromResult<GrainAddress?>(result);
    }

